import java.io.*;
import java.util.*;

public class Main {
    private static String nextNonEmptyLine(BufferedReader br) throws IOException {
        String line;
        while ((line = br.readLine()) != null) {
            if (!line.trim().isEmpty()) {
                return line;
            }
        }
        return null;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String firstLine = nextNonEmptyLine(br);
        if (firstLine == null) {
            // No input provided; nothing to output.
            return;
        }
        int T = Integer.parseInt(firstLine.trim());
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            String nLine = nextNonEmptyLine(br);
            if (nLine == null) {
                // Incomplete test case; treat as invalid.
                sb.append("no");
                if (tc != T - 1) sb.append('\n');
                continue;
            }
            int N = Integer.parseInt(nLine.trim());
            String arrLine = nextNonEmptyLine(br);
            if (arrLine == null) {
                sb.append("no");
                if (tc != T - 1) sb.append('\n');
                continue;
            }
            StringTokenizer st = new StringTokenizer(arrLine);
            int[] a = new int[N];
            for (int i = 0; i < N; i++) {
                if (!st.hasMoreTokens()) {
                    // Not enough numbers; invalid case.
                    a[i] = 0;
                } else {
                    a[i] = Integer.parseInt(st.nextToken());
                }
            }
            boolean ok = true;
            if (N < 13) {
                ok = false;
            } else {
                int l = 0, r = N - 1;
                int prev = 0;
                boolean[] seen = new boolean[8]; // indices 1..7
                int maxVal = 0;
                while (l <= r && ok) {
                    int left = a[l];
                    int right = a[r];
                    if (left != right) {
                        ok = false;
                        break;
                    }
                    if (left < 1 || left > 7) {
                        ok = false;
                        break;
                    }
                    seen[left] = true;
                    maxVal = Math.max(maxVal, left);
                    // ensure non‑decreasing up to the middle
                    if (l > 0) {
                        if (left < prev) {
                            ok = false;
                            break;
                        }
                        if (left > prev + 1) {
                            ok = false;
                            break;
                        }
                    }
                    prev = left;
                    l++;
                    r--;
                }
                if (maxVal != 7) ok = false;
                for (int i = 1; i <= 7; i++) {
                    if (!seen[i]) {
                        ok = false;
                        break;
                    }
                }
            }
            sb.append(ok ? "yes" : "no");
            if (tc != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

